class SearchService:
    """Hybrid search using semantic vectors + SQL keyword/filters with weighted RRF."""

    def __init__(self) -> None:
        self.logger = logging.getLogger("services.search_service")
        self.mode_weights = {
            "semantic": 1.2,
            "keyword": 1.0,
        }

    def search_properties(
        self,
        customer: Customer,
        top_k: int = 10,
        rrf_k: int = 60,
    ) -> List[Dict[str, Any]]:
        try:
            all_properties = database_service.get_properties(
                min_price=customer.budget_min,
                max_price=customer.budget_max * 1.2 if customer.budget_max else None,
                status="active",
            )
            if not all_properties:
                return []

            vector_results = vector_service.search_properties(
                customer,
                all_properties,
                top_k=max(top_k * 3, 20),
            )

            filters = {
                "min_price": customer.budget_min,
                "max_price": customer.budget_max,
                "min_bedrooms": customer.preferred_bedrooms,
                "min_bathrooms": customer.preferred_bathrooms,
                "property_type": customer.preferred_type,
                "neighborhood": customer.location_preference,
            }
            filters = {k: v for k, v in filters.items() if v not in (None, "", 0)}

            keyword_result = database_service.search_properties_advanced(
                search_query="",
                filters=filters,
                page=1,
                per_page=max(top_k * 3, 20),
            )
            keyword_items: List[Property] = keyword_result.get("properties", [])

            fused = self._reciprocal_rank_fusion(
                [
                    (vector_results, self.mode_weights["semantic"], "semantic"),
                    (keyword_items, self.mode_weights["keyword"], "keyword"),
                ],
                rrf_k=rrf_k,
            )

            results: List[Dict[str, Any]] = []
            for property_id, scores in fused[:top_k]:
                prop_obj = self._find_property_object(property_id, vector_results, keyword_items)
                if not prop_obj:
                    continue

                reasons = self._generate_hybrid_reasons(customer, prop_obj)
                results.append(
                    {
                        "property": prop_obj,
                        "hybrid_score": scores["final"] * 100,
                        "semantic_score": scores.get("semantic", 0) * 100,
                        "keyword_score": scores.get("keyword", 0) * 100,
                        "match_reasons": reasons,
                    }
                )

            return results
        except Exception as exc:
            self.logger.error(f"Error in hybrid search: {exc}")
            return []

    def _reciprocal_rank_fusion(
        self,
        ranked_inputs: List[Tuple[List[Any], float, str]],
        rrf_k: int = 60,
    ) -> List[Tuple[int, Dict[str, float]]]:
        total_scores: Dict[int, Dict[str, float]] = defaultdict(lambda: {"final": 0.0, "semantic": 0.0, "keyword": 0.0})

        for items, weight, mode in ranked_inputs:
            for rank, item in enumerate(items):
                if isinstance(item, dict) and "property" in item:
                    prop_id = item["property"].id
                elif hasattr(item, "id"):
                    prop_id = item.id
                else:
                    continue

                score = weight * (1.0 / (rrf_k + rank + 1))
                total_scores[prop_id]["final"] += score
                total_scores[prop_id][mode] += score

        return sorted(total_scores.items(), key=lambda x: x[1]["final"], reverse=True)

    def _find_property_object(
        self,
        property_id: int,
        vector_results: List[Dict[str, Any]],
        keyword_results: List[Property],
    ) -> Optional[Property]:
        for item in keyword_results:
            if item.id == property_id:
                return item

        for item in vector_results:
            prop = item.get("property")
            if prop and prop.id == property_id:
                return prop

        return database_service.get_property(property_id)

    def _generate_hybrid_reasons(self, customer: Customer, property_obj: Property) -> List[str]:
        reasons: List[str] = []
        if customer.budget_max and property_obj.price <= customer.budget_max:
            reasons.append("Within budget")
        if property_obj.bedrooms == customer.preferred_bedrooms:
            reasons.append("Exact bedroom match")
        if (property_obj.property_type or "").lower() == (customer.preferred_type or "").lower():
            reasons.append(f"Matches preferred type ({property_obj.property_type})")
        if (
            property_obj.neighborhood
            and customer.location_preference
            and property_obj.neighborhood.lower() in customer.location_preference.lower()
        ):
            reasons.append("Preferred location")
        return reasons


